export default "<!DOCTYPE html><script type=\"application/json\" id=\"cowork-artifact-meta\">\n{\n  \"name\": \"X Reply Opportunities\",\n  \"schemaVersion\": 1,\n  \"description\": \"Reply Radar — on-demand board of recent, on-topic tweets (startups/health/longevity) worth replying to, each with engagement, an Open-on-X link, and a drafted reply + Copy. Refresh button triggers the ad-hoc x-reply-finder task, which scrapes the user's logged-in X via Claude-in-Chrome (web-search fallback). Seeded with labeled samples.\"\n}\n</script>\n<html lang=\"en\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n<title>Reply Radar — Startups, Health &amp; Longevity</title>\n<style>\n  :root { color-scheme: light; }\n  * { box-sizing: border-box; }\n  body {\n    margin: 0;\n    font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, Helvetica, Arial, sans-serif;\n    color: #0f172a; background: #f5faf9; line-height: 1.5;\n  }\n  .wrap { max-width: 760px; margin: 0 auto; padding: 24px 20px 56px; }\n  header { border-bottom: 2px solid #cfe9e4; padding-bottom: 16px; margin-bottom: 8px; }\n  .kicker { font-size: 12px; font-weight: 700; letter-spacing: .08em; text-transform: uppercase; color: #0d9488; }\n  h1 { font-size: 25px; margin: 6px 0 4px; line-height: 1.2; }\n  .meta { font-size: 13px; color: #64748b; }\n  .banner { background: #fff7ed; border: 1px solid #fed7aa; color: #9a3412; font-size: 12.5px; border-radius: 8px; padding: 9px 12px; margin: 14px 0 4px; }\n  .legend { font-size: 12px; color: #5b7d77; background: #e9f6f3; border: 1px solid #cfe9e4; border-radius: 8px; padding: 8px 12px; margin: 10px 0 2px; }\n  .controls { display: flex; align-items: center; gap: 12px; flex-wrap: wrap; margin: 14px 0 6px; }\n  button.refresh { appearance: none; border: 1px solid #99d6cd; background: #0d9488; color: #fff; font-size: 13px; font-weight: 700; padding: 9px 16px; border-radius: 8px; cursor: pointer; }\n  button.refresh:hover { background: #0b837a; }\n  button.refresh:disabled { opacity: .6; cursor: default; }\n  .status { font-size: 12.5px; color: #64748b; }\n  .hint { font-size: 12px; color: #94a3b8; margin: 6px 2px 14px; }\n\n  .target { background: #fff; border: 1px solid #e2e8f0; border-left: 4px solid #0d9488; border-radius: 10px; padding: 14px 16px; margin: 12px 0; }\n  .thead { display: flex; align-items: center; gap: 8px; flex-wrap: wrap; font-size: 13px; }\n  .thead .who { color: #0f766e; font-weight: 700; text-decoration: none; }\n  .thead .who:hover { text-decoration: underline; }\n  .thead .when { color: #94a3b8; }\n  .thead .metrics { color: #64748b; }\n  .bucket { margin-left: auto; font-size: 11px; font-weight: 700; text-transform: uppercase; letter-spacing: .04em; border-radius: 999px; padding: 2px 9px; }\n  .b-long { color: #6d28d9; background: #ede9fe; }\n  .b-health { color: #0f766e; background: #d8f3ee; }\n  .b-startup { color: #1d4ed8; background: #e6effe; }\n  .sample { color: #92400e; background: #fef3c7; font-size: 11px; font-weight: 700; border-radius: 999px; padding: 2px 9px; }\n  .ttext { margin: 9px 0 10px; font-size: 14.5px; color: #1e293b; }\n  .actions { margin-bottom: 10px; }\n  a.openx { font-size: 12.5px; font-weight: 600; color: #0d9488; text-decoration: none; border: 1px solid #99d6cd; border-radius: 6px; padding: 3px 9px; }\n  a.openx:hover { background: #e9f6f3; }\n\n  .reply { background: #f3faf8; border: 1px solid #d6ece7; border-radius: 8px; padding: 10px 12px; }\n  .reply-head { display: flex; align-items: center; justify-content: space-between; gap: 8px; font-size: 11px; font-weight: 700; text-transform: uppercase; letter-spacing: .05em; color: #0f766e; margin-bottom: 7px; }\n  .reply-body { white-space: pre-line; font-size: 13.5px; color: #0f172a; line-height: 1.5; }\n  button.copy { appearance: none; border: 1px solid #99d6cd; background: #fff; color: #0f172a; font-size: 11px; font-weight: 600; padding: 3px 10px; border-radius: 6px; cursor: pointer; white-space: nowrap; }\n  button.copy:hover { background: #e9f6f3; }\n  footer { margin-top: 26px; font-size: 12px; color: #94a3b8; border-top: 1px solid #cfe9e4; padding-top: 14px; }\n</style>\n</head>\n<body>\n<div class=\"wrap\">\n  <header>\n    <div class=\"kicker\">Reply Radar · On-demand</div>\n    <h1>Tweets Worth Replying To</h1>\n    <div class=\"meta\" id=\"asof\">As of Saturday, June 27, 2026 · 12:42 AM</div>\n  </header>\n\n  <div class=\"banner\" id=\"sourceBanner\">\n    These are <b>labeled samples</b> to show the format. If Chrome isn’t connected it falls back to web search.\n  </div>\n\n  <div class=\"legend\">\n    Picked for: <b>recent</b> (last ~24h) · <b>on-topic</b> (startups / health / longevity) · enough reach to be seen · <b>not</b> buried under hundreds of replies.\n  </div>\n\n  \n  \n\n  <div class=\"target\">\n    <div class=\"thead\"><a class=\"who\" href=\"https://www.aging-us.com/news-room/rapamycin-shows-limited-evidence-for-longevity-benefits-in-healthy-adults\" target=\"_blank\" rel=\"noopener\">Aging-US</a><span class=\"when\">· —</span><span class=\"metrics\">—</span><span class=\"bucket b-long\">Longevity</span></div>\n    <p class=\"ttext\">New review: rapamycin shows limited evidence for longevity benefit in healthy adults. Mice gain up to 28% lifespan; no human trial has used all-cause mortality as a primary endpoint.</p>\n    <div class=\"actions\"><a class=\"openx\" href=\"https://www.aging-us.com/news-room/rapamycin-shows-limited-evidence-for-longevity-benefits-in-healthy-adults\" target=\"_blank\" rel=\"noopener\">Open on X ↗</a></div>\n    <div class=\"reply\">\n      <div class=\"reply-head\"><span>✎ Suggested reply</span><button class=\"copy\" onclick=\"copyReply(this)\">Copy</button></div>\n      <div class=\"reply-body\">The animal-to-human gap is the whole story.\nMice see ~28% lifespan gains; no human trial has even used mortality as an endpoint.\nPEARL showed it's likely safe for a year — but safe isn't life-extending.</div>\n    </div>\n  </div>\n\n  <div class=\"target\">\n    <div class=\"thead\"><a class=\"who\" href=\"https://www.businesswire.com/news/home/20260623150207/en/Pathway-Labs-Announces-Worlds-First-FDA-Clearance-for-Multicondition-AI-in-Cardiology-and-Partnership-with-OpenEvidence\" target=\"_blank\" rel=\"noopener\">Pathway Labs</a><span class=\"when\">· —</span><span class=\"metrics\">—</span><span class=\"bucket b-health\">Health</span></div>\n    <p class=\"ttext\">Pathway Labs gets the world's first FDA clearance for multicondition AI in cardiology — EchoNext reads a standard 12-lead ECG to flag structural heart disease across six indications.</p>\n    <div class=\"actions\"><a class=\"openx\" href=\"https://www.businesswire.com/news/home/20260623150207/en/Pathway-Labs-Announces-Worlds-First-FDA-Clearance-for-Multicondition-AI-in-Cardiology-and-Partnership-with-OpenEvidence\" target=\"_blank\" rel=\"noopener\">Open on X ↗</a></div>\n    <div class=\"reply\">\n      <div class=\"reply-head\"><span>✎ Suggested reply</span><button class=\"copy\" onclick=\"copyReply(this)\">Copy</button></div>\n      <div class=\"reply-body\">The smart part: it reads structural heart disease off a standard 12-lead ECG — no new hardware, just data clinics already collect.\nSix indications in one clearance is rare.\nThe number I want next: false-positive rate in primary care.</div>\n    </div>\n  </div>\n\n  <div class=\"target\">\n    <div class=\"thead\"><a class=\"who\" href=\"https://www.fiercehealthcare.com/health-tech/fierce-healthcare-fundraising-tracker-26\" target=\"_blank\" rel=\"noopener\">Lassie AI</a><span class=\"when\">· —</span><span class=\"metrics\">—</span><span class=\"bucket b-startup\">Startups</span></div>\n    <p class=\"ttext\">Lassie lands $35M Series A led by a16z for an AI agent that pulls reimbursements from insurance portals, reconciles them against records, and verifies the funds in the bank.</p>\n    <div class=\"actions\"><a class=\"openx\" href=\"https://www.fiercehealthcare.com/health-tech/fierce-healthcare-fundraising-tracker-26\" target=\"_blank\" rel=\"noopener\">Open on X ↗</a></div>\n    <div class=\"reply\">\n      <div class=\"reply-head\"><span>✎ Suggested reply</span><button class=\"copy\" onclick=\"copyReply(this)\">Copy</button></div>\n      <div class=\"reply-body\">An AI agent that reconciles reimbursements to the bank is a real autonomy bet for revenue cycle.\nThe hard part isn't reading portals — it's being trusted near money without a human check.\nWhat stays human-in-the-loop?</div>\n    </div>\n  </div>\n\n  <div class=\"target\">\n    <div class=\"thead\"><a class=\"who\" href=\"https://www.nad.com/news/an-irritated-peter-attia-calls-out-biohackers-like-bryan-johnson\" target=\"_blank\" rel=\"noopener\">Peter Attia</a><span class=\"when\">· —</span><span class=\"metrics\">—</span><span class=\"bucket b-long\">Longevity</span></div>\n    <p class=\"ttext\">Peter Attia calls out biohackers like Bryan Johnson — says he's not opposed to people wasting money, he's opposed to people wasting mind share on unproven protocols.</p>\n    <div class=\"actions\"><a class=\"openx\" href=\"https://www.nad.com/news/an-irritated-peter-attia-calls-out-biohackers-like-bryan-johnson\" target=\"_blank\" rel=\"noopener\">Open on X ↗</a></div>\n    <div class=\"reply\">\n      <div class=\"reply-head\"><span>✎ Suggested reply</span><button class=\"copy\" onclick=\"copyReply(this)\">Copy</button></div>\n      <div class=\"reply-body\">The \"wasting mind share, not money\" line is the sharp part.\nThe cost of 100 supplements isn't the dollars — it's treating unproven shots like follistatin as settled.\nAttention is the scarce resource in longevity, not capital.</div>\n    </div>\n  </div>\n\n  <div class=\"target\">\n    <div class=\"thead\"><a class=\"who\" href=\"https://www.sciencedaily.com/releases/2026/06/260614011841.htm\" target=\"_blank\" rel=\"noopener\">ScienceDaily</a><span class=\"when\">· —</span><span class=\"metrics\">—</span><span class=\"bucket b-health\">Health</span></div>\n    <p class=\"ttext\">New study (ENDO 2026): people on GLP-1 drugs took fewer steps and exercised less after starting. The biggest activity drop was in men and people with musculoskeletal pain.</p>\n    <div class=\"actions\"><a class=\"openx\" href=\"https://www.sciencedaily.com/releases/2026/06/260614011841.htm\" target=\"_blank\" rel=\"noopener\">Open on X ↗</a></div>\n    <div class=\"reply\">\n      <div class=\"reply-head\"><span>✎ Suggested reply</span><button class=\"copy\" onclick=\"copyReply(this)\">Copy</button></div>\n      <div class=\"reply-body\">This is the quiet failure mode of GLP-1s.\nWeight comes off but movement drops — and the biggest decline hit men and people with joint pain, exactly who needs to keep muscle.\nWeight down with activity down isn't health up.</div>\n    </div>\n  </div>\n\n  <div class=\"target\">\n    <div class=\"thead\"><a class=\"who\" href=\"https://www.fiercehealthcare.com/ai-and-machine-learning/amperos-health-secures-16m-series-funding-announces-industrys-new-first-ai\" target=\"_blank\" rel=\"noopener\">Amperos Health</a><span class=\"when\">· —</span><span class=\"metrics\">—</span><span class=\"bucket b-startup\">Startups</span></div>\n    <p class=\"ttext\">Amperos Health raises $16M Series A for an AI-native denial management tool — automating the insurance appeals where providers lose the most revenue.</p>\n    <div class=\"actions\"><a class=\"openx\" href=\"https://www.fiercehealthcare.com/ai-and-machine-learning/amperos-health-secures-16m-series-funding-announces-industrys-new-first-ai\" target=\"_blank\" rel=\"noopener\">Open on X ↗</a></div>\n    <div class=\"reply\">\n      <div class=\"reply-head\"><span>✎ Suggested reply</span><button class=\"copy\" onclick=\"copyReply(this)\">Copy</button></div>\n      <div class=\"reply-body\">Denials are a smart wedge — concrete rules, real dollars, a clear win condition.\nThe moat question is durability: payers rewrite denial logic constantly.\nHow fast does the model adapt when the rules shift under it?</div>\n    </div>\n  </div>\n\n  <div class=\"target\">\n    <div class=\"thead\"><a class=\"who\" href=\"https://www.linkedin.com/posts/mkaeberlein_lets-be-clear-bryan-johnson-is-not-a-credible-activity-7315347977630298112-HGNw\" target=\"_blank\" rel=\"noopener\">Matt Kaeberlein</a><span class=\"when\">· —</span><span class=\"metrics\">—</span><span class=\"bucket b-long\">Longevity</span></div>\n    <p class=\"ttext\">Matt Kaeberlein: Bryan Johnson's rapamycin claims are misleading. The molecule has strong animal data; overselling it with n=1 anecdotes undercuts the real science.</p>\n    <div class=\"actions\"><a class=\"openx\" href=\"https://www.linkedin.com/posts/mkaeberlein_lets-be-clear-bryan-johnson-is-not-a-credible-activity-7315347977630298112-HGNw\" target=\"_blank\" rel=\"noopener\">Open on X ↗</a></div>\n    <div class=\"reply\">\n      <div class=\"reply-head\"><span>✎ Suggested reply</span><button class=\"copy\" onclick=\"copyReply(this)\">Copy</button></div>\n      <div class=\"reply-body\">Right to separate the molecule from the messenger.\nRapamycin has the best animal lifespan data we've got — which is exactly why n=1 hype hurts the case.\nDosing trials move this forward; one person's protocol doesn't.</div>\n    </div>\n  </div>\n\n  <div class=\"target\">\n    <div class=\"thead\"><a class=\"who\" href=\"https://med.stanford.edu/news/all-news/2026/06/muscle-glp-1.html\" target=\"_blank\" rel=\"noopener\">Stanford Medicine</a><span class=\"when\">· —</span><span class=\"metrics\">—</span><span class=\"bucket b-health\">Health</span></div>\n    <p class=\"ttext\">Stanford: a drug already in trials for age-related muscle loss helped preserve muscle in mice on semaglutide, which lost ~25% body weight but shed muscle along with fat.</p>\n    <div class=\"actions\"><a class=\"openx\" href=\"https://med.stanford.edu/news/all-news/2026/06/muscle-glp-1.html\" target=\"_blank\" rel=\"noopener\">Open on X ↗</a></div>\n    <div class=\"reply\">\n      <div class=\"reply-head\"><span>✎ Suggested reply</span><button class=\"copy\" onclick=\"copyReply(this)\">Copy</button></div>\n      <div class=\"reply-body\">Pairing a muscle-preserving drug with semaglutide is the right instinct.\nMice lost ~25% body weight but gave up muscle with the fat — and muscle doesn't return the way fat does.\nOpen question: does it hold outside mice?</div>\n    </div>\n  </div>\n\n  <div class=\"target\">\n    <div class=\"thead\"><a class=\"who\" href=\"https://www.statnews.com/2026/05/22/retro-biosciences-longevity-valuation/\" target=\"_blank\" rel=\"noopener\">Retro Biosciences</a><span class=\"when\">· —</span><span class=\"metrics\">—</span><span class=\"bucket b-startup\">Startups</span></div>\n    <p class=\"ttext\">Retro Biosciences, the Sam Altman-backed longevity startup, raised more money at a $1.8B valuation — still with no approved product.</p>\n    <div class=\"actions\"><a class=\"openx\" href=\"https://www.statnews.com/2026/05/22/retro-biosciences-longevity-valuation/\" target=\"_blank\" rel=\"noopener\">Open on X ↗</a></div>\n    <div class=\"reply\">\n      <div class=\"reply-head\"><span>✎ Suggested reply</span><button class=\"copy\" onclick=\"copyReply(this)\">Copy</button></div>\n      <div class=\"reply-body\">A $1.8B valuation with no approved product is a bet on the platform, not a drug.\nAltman's backing buys runway most aging biotechs never get.\nThe test: does cellular reprogramming reach a human trial before the capital cools?</div>\n    </div>\n  </div>\n\n  <div class=\"target\">\n    <div class=\"thead\"><a class=\"who\" href=\"https://www.rapamycin.news/t/gene-therapy-for-aging-and-longevity-paper-june-2026/25380\" target=\"_blank\" rel=\"noopener\">Rapamycin News</a><span class=\"when\">· —</span><span class=\"metrics\">—</span><span class=\"bucket b-long\">Longevity</span></div>\n    <p class=\"ttext\">New June 2026 paper argues gene therapy could slow aging by directly targeting longevity pathways — framing aging as partly genetically modifiable.</p>\n    <div class=\"actions\"><a class=\"openx\" href=\"https://www.rapamycin.news/t/gene-therapy-for-aging-and-longevity-paper-june-2026/25380\" target=\"_blank\" rel=\"noopener\">Open on X ↗</a></div>\n    <div class=\"reply\">\n      <div class=\"reply-head\"><span>✎ Suggested reply</span><button class=\"copy\" onclick=\"copyReply(this)\">Copy</button></div>\n      <div class=\"reply-body\">Gene therapy for aging lives or dies on delivery, not target choice.\nWe've known the candidate pathways for years — getting vectors to the right tissues at safe, repeatable doses is the hard part.\nWhich delivery method does the paper back?</div>\n    </div>\n  </div>\n\n  <div class=\"target\">\n    <div class=\"thead\"><a class=\"who\" href=\"https://www.sciencedaily.com/releases/2026/06/260619020504.htm\" target=\"_blank\" rel=\"noopener\">ScienceDaily</a><span class=\"when\">· —</span><span class=\"metrics\">—</span><span class=\"bucket b-health\">Health</span></div>\n    <p class=\"ttext\">Experts: Ozempic changed obesity treatment, but the real revolution is GLP-1s expanding into addiction, liver, and heart disease. Obesity was just the first indication.</p>\n    <div class=\"actions\"><a class=\"openx\" href=\"https://www.sciencedaily.com/releases/2026/06/260619020504.htm\" target=\"_blank\" rel=\"noopener\">Open on X ↗</a></div>\n    <div class=\"reply\">\n      <div class=\"reply-head\"><span>✎ Suggested reply</span><button class=\"copy\" onclick=\"copyReply(this)\">Copy</button></div>\n      <div class=\"reply-body\">The bigger shift won't be more weight loss — it's GLP-1s moving into addiction, liver, and heart disease.\nObesity was just the indication that paid for the trials.\nWhich non-metabolic use do you think clears first?</div>\n    </div>\n  </div>\n\n  <div class=\"target\">\n    <div class=\"thead\"><a class=\"who\" href=\"https://www.fiercehealthcare.com/health-tech/fierce-healthcare-fundraising-tracker-26\" target=\"_blank\" rel=\"noopener\">Clair Health</a><span class=\"when\">· —</span><span class=\"metrics\">—</span><span class=\"bucket b-startup\">Startups</span></div>\n    <p class=\"ttext\">Clair Health picks up $11.6M for a women's health monitoring wearable — a bracelet and app launching November 2026 from two recent Stanford grads.</p>\n    <div class=\"actions\"><a class=\"openx\" href=\"https://www.fiercehealthcare.com/health-tech/fierce-healthcare-fundraising-tracker-26\" target=\"_blank\" rel=\"noopener\">Open on X ↗</a></div>\n    <div class=\"reply\">\n      <div class=\"reply-head\"><span>✎ Suggested reply</span><button class=\"copy\" onclick=\"copyReply(this)\">Copy</button></div>\n      <div class=\"reply-body\">Women's health is one of the most under-instrumented areas in wearables, so the gap is real.\nThe challenge isn't the bracelet — it's proving the signal changes decisions.\nWhat is Clair measuring that Oura and Apple miss?</div>\n    </div>\n  </div>\n\n  <footer>\n    On-demand reply finder. Each refresh reads your logged-in X (Premium+ / X Pro) for recent, on-topic posts worth replying to, ranks them, and drafts a reply for each — drafts only, nothing is posted. If Chrome isn’t connected it falls back to web search. Samples above are illustrative until the first live refresh.\n  </footer>\n</div>\n\n<script>\n  function setStatus(){}\n  function refresh(){}\n  \n  function copyReply(btn){\n    var box = btn.closest('.reply').querySelector('.reply-body');\n    if(!box) return;\n    var text = box.textContent.split('\\n').map(function(s){ return s.trim(); }).join('\\n').replace(/\\n{3,}/g, '\\n\\n').trim();\n    var label = btn.getAttribute('data-label') || btn.textContent;\n    btn.setAttribute('data-label', label);\n    function ok(){ btn.textContent = 'Copied!'; setTimeout(function(){ btn.textContent = label; }, 1500); }\n    function fail(){ btn.textContent = 'Select & copy'; setTimeout(function(){ btn.textContent = label; }, 2000); }\n    if(navigator.clipboard && navigator.clipboard.writeText){\n      navigator.clipboard.writeText(text).then(ok).catch(function(){ tryExec(text) ? ok() : fail(); });\n    } else { tryExec(text) ? ok() : fail(); }\n  }\n  function tryExec(text){\n    try {\n      var ta = document.createElement('textarea'); ta.value = text;\n      ta.style.position = 'fixed'; ta.style.top = '-1000px';\n      document.body.appendChild(ta); ta.focus(); ta.select();\n      var r = document.execCommand('copy'); document.body.removeChild(ta); return r;\n    } catch(e){ return false; }\n  }\n</script>\n</body>\n</html>";
